select * from ( SELECT TPPSD.CARGO_INFO_ID, TPPSD.STOREHOUSE_ID, T3.TRUST_NO, TPPSD.STOREHOUSE_NAME, TPPSD.REGION_ID, TPPSD.REGION_NAME, TPPSD.MASS_ID, TPPSD.MASS_NAME, TBCI.CARGO_INFO_NO, NVL(MAX(TPPSD1.INOUT_STORAGE_CODE),'0000') INOUT_STORAGE_CODE, NVL(MAX(TPPSD1.INOUT_STORAGE_NAME),'未清场') INOUT_STORAGE_NAME, TBCI.SHIP_NAME, TDSI.VOYAGE, MAX(TPPSD.COMPANY_NAME) COMPANY_NAME, CASE WHEN TBCI.SHIPVOYAGE_ITEM_ID IS NOT NULL THEN TO_CHAR( TBCI.SHIP_NAME ) || '_' || TO_CHAR( TDSI.VOYAGE ) END SHIP_NAME_VOYAGE, TBCI.TRADE_TYPE TRADE_TYPE, TBCI.CARGO_OWNER_NAME CARGO_OWNER_NAME, TBCI.CARGO_AGENT_NAME CARGO_AGENT_NAME, TBCI.CARGO_NAME CARGO_NAME, TO_CHAR( MIN( TPPSD.INOUT_DATE ), 'YYYY-MM-DD' ) INOUT_DATE, TBCI.PACKING_NAME PACKING_NAME, SUM(TPPSD.QUANTITY) QUANTITY, SUM(TPPSD.TON) TON, TO_CHAR( TBCI.COMPANY_NAME ) || '/' || TO_CHAR( TBCI.CARGO_OWNER_NAME ) || '/' || TO_CHAR( TBCI.CARGO_AGENT_NAME ) || '/' || TO_CHAR( TBCI.CARGO_NAME ) || '/' || TO_CHAR( TBCI.TRADE_TYPE ) || '/' || TO_CHAR( TBCI.PACKING_NAME ) CARGO_INFO_LABEL FROM T_PRD_PORT_STORAGE_DETAIL TPPSD JOIN T_BUS_CARGO_INFO TBCI ON TPPSD.CARGO_INFO_ID = TBCI.ID LEFT JOIN ( SELECT MASS_ID, REGION_ID, CARGO_INFO_ID, INOUT_STORAGE_CODE, INOUT_STORAGE_NAME FROM T_PRD_PORT_STORAGE_DETAIL ) TPPSD1 ON TPPSD1.CARGO_INFO_ID = TPPSD.CARGO_INFO_ID AND TPPSD1.REGION_ID = TPPSD.REGION_ID AND TPPSD1.MASS_ID = TPPSD.MASS_ID AND TPPSD1.INOUT_STORAGE_CODE = '50' LEFT JOIN ( select LISTAGG(TRUST_NO, ',') WITHIN GROUP (ORDER BY TRUST_NO) TRUST_NO,CARGO_INFO_ID FROM ( select TRUST_NO,TBTC.CARGO_INFO_ID FROM T_BUS_TRUST_CARGO TBTC LEFT JOIN T_BUS_TRUST TBT ON TBTC.TRUST_ID = TBT.ID GROUP BY TRUST_NO,TBTC.CARGO_INFO_ID ) GROUP BY CARGO_INFO_ID ) T3 ON TBCI.ID = T3.CARGO_INFO_ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM TDSI ON TBCI.SHIPVOYAGE_ITEM_ID = TDSI.ID
AND (TPPSD.STOREHOUSE_NAME LIKE #{queryStr_like, jdbcType=VARCHAR} OR TPPSD.REGION_NAME LIKE #{queryStr_like, jdbcType=VARCHAR} OR TPPSD.MASS_NAME LIKE #{queryStr_like, jdbcType=VARCHAR})
AND TBCI.SCN LIKE #{scn_like, jdbcType=VARCHAR}
AND TPPSD.COMPANY_ID = #{companyId, jdbcType=BIGINT}
AND TBCI.SHIPVOYAGE_ITEM_ID = #{shipvoyageItemId, jdbcType=BIGINT}
AND TBCI.TRADE_TYPE = #{tradeType, jdbcType=VARCHAR}
AND TPPSD.STOREHOUSE_ID = #{storehouseId, jdbcType=BIGINT}
AND TPPSD.REGION_ID = #{regionId, jdbcType=BIGINT}
AND TPPSD.MASS_ID = #{massId, jdbcType=BIGINT}
AND TBCI.CARGO_OWNER_ID = #{cargoOwnerId, jdbcType=BIGINT}
AND TBCI.CARGO_NAME LIKE #{cargoNameLike, jdbcType=VARCHAR}
AND TBCI.PACKING_CODE = #{packingCode, jdbcType=VARCHAR}
AND TBCI.CARGO_INFO_NO LIKE #{cargoInfoNoLike, jdbcType=VARCHAR}
AND TBCI.SHIP_NAME LIKE #{shipNameLike, jdbcType=VARCHAR}
AND TDSI.VOYAGE = #{voyage}
GROUP BY TPPSD.CARGO_INFO_ID, T3.TRUST_NO, TPPSD.STOREHOUSE_ID, TPPSD.STOREHOUSE_NAME, TPPSD.REGION_ID, TPPSD.REGION_NAME, TPPSD.MASS_ID, TPPSD.MASS_NAME, TBCI.CARGO_INFO_NO, TBCI.SHIPVOYAGE_ITEM_ID, TBCI.SHIP_NAME, TDSI.VOYAGE, TBCI.TRADE_TYPE, TBCI.CARGO_OWNER_NAME, TBCI.CARGO_AGENT_NAME, TBCI.CARGO_NAME, TBCI.PACKING_NAME, TPPSD1.INOUT_STORAGE_CODE, TPPSD1.INOUT_STORAGE_NAME, TBCI.COMPANY_NAME ) M where INOUT_STORAGE_NAME = '清场'

SELECT
SUM(TPPSD.QUANTITY) QUANTITY,
SUM(TPPSD.TON) TON
FROM T_PRD_PORT_STORAGE_DETAIL TPPSD
JOIN T_BUS_CARGO_INFO TBCI ON TPPSD.CARGO_INFO_ID = TBCI.ID
LEFT JOIN T_DIS_SHIPVOYAGE_ITEM TDSI ON TBCI.SHIPVOYAGE_ITEM_ID = TDSI.ID

    EXISTS(select * FROM (select  CARGO_INFO_ID,PORT_STORAGE_ID from T_PRD_PORT_STORAGE_DETAIL where INOUT_STORAGE_CODE = '50'  group by PORT_STORAGE_ID, CARGO_INFO_ID ) tmp  where tmp. CARGO_INFO_ID =TPPSD.CARGO_INFO_ID and tmp.PORT_STORAGE_ID = TPPSD.PORT_STORAGE_ID)

        AND TPPSD.COMPANY_ID = #{companyId, jdbcType=BIGINT}


        AND TBCI.SHIPVOYAGE_ITEM_ID = #{shipvoyageItemId, jdbcType=BIGINT}


        AND TBCI.TRADE_TYPE = #{tradeType, jdbcType=VARCHAR}


        AND TPPSD.STOREHOUSE_ID = #{storehouseId, jdbcType=BIGINT}


        AND TPPSD.REGION_ID = #{regionId, jdbcType=BIGINT}


        AND TPPSD.MASS_ID = #{massId, jdbcType=BIGINT}


        AND TBCI.CARGO_OWNER_ID = #{cargoOwnerId, jdbcType=BIGINT}



        AND TBCI.CARGO_NAME LIKE #{cargoNameLike, jdbcType=VARCHAR}


        AND TBCI.PACKING_CODE = #{packingCode, jdbcType=VARCHAR}



        AND TBCI.CARGO_INFO_NO LIKE #{cargoInfoNoLike, jdbcType=VARCHAR}



        AND TBCI.SHIP_NAME LIKE #{shipNameLike, jdbcType=VARCHAR}


        AND TDSI.VOYAGE = #{voyage}

select * from ( SELECT TPPSD.CARGO_INFO_ID, TPPSD.STOREHOUSE_ID, T3.TRUST_NO, TPPSD.STOREHOUSE_NAME, TPPSD.REGION_ID, TPPSD.REGION_NAME, TPPSD.MASS_ID, TPPSD.MASS_NAME, NVL(MAX(TPPSD1.INOUT_STORAGE_CODE),'0000') INOUT_STORAGE_CODE, NVL(MAX(TPPSD1.INOUT_STORAGE_NAME),'未清场') INOUT_STORAGE_NAME, TBCI.CARGO_INFO_NO, MAX(TPPSD.COMPANY_NAME) COMPANY_NAME, CASE WHEN TBCI.SHIPVOYAGE_ITEM_ID IS NOT NULL THEN TO_CHAR( TBCI.SHIP_NAME ) || '_' || TO_CHAR( TDSI.VOYAGE ) END SHIP_NAME_VOYAGE, TBCI.TRADE_TYPE TRADE_TYPE, TBCI.CARGO_OWNER_NAME CARGO_OWNER_NAME, TBCI.CARGO_AGENT_NAME CARGO_AGENT_NAME, TBCI.CARGO_NAME CARGO_NAME, TO_CHAR( MAX( TPPSD.INOUT_DATE ), 'YYYY-MM-DD' ) INOUT_DATE, TBCI.PACKING_NAME PACKING_NAME, SUM(TPPSD.QUANTITY) QUANTITY, SUM(TPPSD.TON) TON, TO_CHAR( TBCI.COMPANY_NAME ) || '/' || TO_CHAR( TBCI.CARGO_OWNER_NAME ) || '/' || TO_CHAR( TBCI.CARGO_AGENT_NAME ) || '/' || TO_CHAR( TBCI.CARGO_NAME ) || '/' || TO_CHAR( TBCI.TRADE_TYPE ) || '/' || TO_CHAR( TBCI.PACKING_NAME ) CARGO_INFO_LABEL FROM T_PRD_PORT_STORAGE_DETAIL TPPSD JOIN T_BUS_CARGO_INFO TBCI ON TPPSD.CARGO_INFO_ID = TBCI.ID LEFT JOIN ( SELECT MASS_ID, REGION_ID, CARGO_INFO_ID, INOUT_STORAGE_CODE, INOUT_STORAGE_NAME FROM T_PRD_PORT_STORAGE_DETAIL ) TPPSD1 ON TPPSD1.CARGO_INFO_ID = TPPSD.CARGO_INFO_ID AND TPPSD1.REGION_ID = TPPSD.REGION_ID AND TPPSD1.MASS_ID = TPPSD.MASS_ID AND TPPSD1.INOUT_STORAGE_CODE = '50' LEFT JOIN ( select LISTAGG(TRUST_NO, ',') WITHIN GROUP (ORDER BY TRUST_NO) TRUST_NO,CARGO_INFO_ID FROM ( select TRUST_NO,TBTC.CARGO_INFO_ID FROM T_BUS_TRUST_CARGO TBTC LEFT JOIN T_BUS_TRUST TBT ON TBTC.TRUST_ID = TBT.ID GROUP BY TRUST_NO,TBTC.CARGO_INFO_ID ) GROUP BY CARGO_INFO_ID ) T3 ON TBCI.ID = T3.CARGO_INFO_ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM TDSI ON TBCI.SHIPVOYAGE_ITEM_ID = TDSI.ID
AND (TPPSD.STOREHOUSE_NAME LIKE #{queryStr_like, jdbcType=VARCHAR} OR TPPSD.REGION_NAME LIKE #{queryStr_like, jdbcType=VARCHAR} OR TPPSD.MASS_NAME LIKE #{queryStr_like, jdbcType=VARCHAR})
AND TBCI.SCN LIKE #{scn_like, jdbcType=VARCHAR}
AND TPPSD.COMPANY_ID = #{companyId, jdbcType=BIGINT}
AND TBCI.SHIPVOYAGE_ITEM_ID = #{shipvoyageItemId, jdbcType=BIGINT}
AND TBCI.TRADE_TYPE = #{tradeType, jdbcType=VARCHAR}
AND TPPSD.STOREHOUSE_ID = #{storehouseId, jdbcType=BIGINT}
AND TPPSD.REGION_ID = #{regionId, jdbcType=BIGINT}
AND TPPSD.MASS_ID = #{massId, jdbcType=BIGINT}
AND TBCI.CARGO_OWNER_ID = #{cargoOwnerId, jdbcType=BIGINT}
AND TBCI.CARGO_NAME LIKE #{cargoNameLike, jdbcType=VARCHAR}
AND TBCI.PACKING_CODE = #{packingCode, jdbcType=VARCHAR}
AND TBCI.CARGO_INFO_NO LIKE #{cargoInfoNoLike, jdbcType=VARCHAR}
GROUP BY TPPSD.CARGO_INFO_ID, T3.TRUST_NO, TPPSD.STOREHOUSE_ID, TPPSD.STOREHOUSE_NAME, TPPSD.REGION_ID, TPPSD.REGION_NAME, TPPSD.MASS_ID, TPPSD.MASS_NAME, TBCI.CARGO_INFO_NO, TBCI.SHIPVOYAGE_ITEM_ID, TBCI.SHIP_NAME, TDSI.VOYAGE, TBCI.TRADE_TYPE, TBCI.CARGO_OWNER_NAME, TBCI.CARGO_AGENT_NAME, TBCI.CARGO_NAME, TBCI.PACKING_NAME, TBCI.COMPANY_NAME, TPPSD1.INOUT_STORAGE_CODE, TPPSD1.INOUT_STORAGE_NAME ) M where INOUT_STORAGE_NAME = '清场'
